css:
.ps-research-trail { margin-block-start: var(--pds-space-4); padding: var(--pds-space-2); background: var(--pds-surface-layer-accent); border-inline-start: 3px solid var(--pds-border-subtle); }
.ps-research-trail__summary { font-family: var(--pds-font-sans); font-size: 0.875rem; font-weight: 600; color: var(--pds-text-secondary); cursor: pointer; list-style: revert; user-select: none; }
.ps-research-trail__summary:focus-visible { outline: 2px solid var(--pds-focus-ring); outline-offset: 2px; }
.ps-research-trail__body { margin-block-start: var(--pds-space-2); }
.ps-research-trail__heading { font-family: var(--pds-font-sans); font-size: 0.9375rem; font-weight: 600; margin: var(--pds-space-2) 0 var(--pds-space-1); padding-inline-start: var(--pds-space-1); border-inline-start: 3px solid transparent; }
.ps-research-trail__heading--done { border-inline-start-color: var(--pds-status-success); }
.ps-research-trail__heading--suggested { border-inline-start-color: var(--pds-brand-blue-60); }
.ps-research-trail__heading--open { border-inline-start-color: var(--pds-status-warn); }
.ps-research-trail__list { margin: 0; padding-inline-start: var(--pds-space-2); font-size: 0.875rem; line-height: 1.6; }
.ps-research-trail__list li { padding-block: 0.125rem; color: var(--pds-text-primary); }
